export const CARDS = [

  // ── DAY 1 ────────────────────────────────────────────────────────────
  { id: 1, cat: "FOUNDING", term: "Articles of Confederation", bullets: ["America's first governing document (1781–1789) — gave most power to individual states", "Congress had no power to tax, regulate trade, or enforce its own laws", "Led to economic chaos; exposed by Shays' Rebellion (1786)", "Replaced by the Constitution after a convention in 1787"] },
  { id: 2, cat: "FOUNDING", term: "Judicial Review", bullets: ["The power of the Supreme Court to strike down laws that violate the Constitution", "Established in Marbury v. Madison (1803) by Chief Justice John Marshall", "Makes the judiciary a check on both Congress and the President", "Not written in the Constitution — part of the 'unwritten constitution'"] },
  { id: 3, cat: "FOUNDING", term: "Electoral College", bullets: ["Indirect system for electing the President — citizens vote for electors, not the president directly", "Each state gets electors equal to its senators + representatives", "A candidate needs 270 electoral votes to win", "Criticized as undemocratic; small states hold proportionally more influence"] },
  { id: 4, cat: "FOUNDING", term: "Checks & Balances", bullets: ["Each branch of government can limit the power of the other two", "Examples: Congress can override a veto; President nominates justices; Court can strike down laws", "Prevents any one branch from accumulating too much power", "Based on Montesquieu's theory of separation of powers"] },
  { id: 5, cat: "FOUNDING", term: "Bill of Rights", bullets: ["The first 10 amendments to the Constitution, ratified in 1791", "Protects speech, religion, press, assembly, right to bear arms, and more", "Guarantees due process and protects against unreasonable search and seizure (4th Amendment)", "Added to win Anti-Federalist support for ratifying the Constitution"] },
  { id: 6, cat: "FOUNDING", term: "Federalism", bullets: ["Division of power between the national government and state governments", "Federal-only powers: declaring war, printing money, foreign policy", "Concurrent (shared) powers: taxing, roads, law enforcement", "10th Amendment reserves unlisted powers to the states or the people"] },
  { id: 7, cat: "FOUNDING", term: "Appalachian Mountains", bullets: ["Mountain range running along the eastern United States", "Served as a natural barrier to westward expansion in the colonial era", "Proclamation of 1763 forbade colonists from settling beyond them — a major grievance", "Eventually crossed as America expanded westward after independence"] },
  { id: 8, cat: "CIVIL RIGHTS", term: "Suffrage", bullets: ["The right to vote", "Originally limited to white male property owners", "15th Amendment (1870): gave Black men the vote; 19th Amendment (1920): gave women the vote", "26th Amendment (1971) lowered the voting age from 21 to 18"] },
  { id: 9, cat: "FOUNDING", term: "Manifest Destiny", bullets: ["Belief that Americans were divinely destined to expand from Atlantic to Pacific", "Justified westward expansion and displacement of Native American peoples", "Led to the Mexican-American War (1846–1848) and vast territorial acquisitions", "Drove mass migration on the Oregon Trail; fueled the California Gold Rush (1849)"] },
  { id: 10, cat: "GILDED AGE", term: "Populism", bullets: ["1890s movement representing farmers and working class against powerful elites", "Opposed banks, railroads, and industrialists who exploited ordinary Americans", "Key demands: silver coinage, graduated income tax, direct election of senators", "William Jennings Bryan was its leader; forerunner of the Progressive movement"] },
  { id: 11, cat: "PROG. ERA", term: "Prohibition", bullets: ["18th Amendment (1919) banned manufacture, sale, and transport of alcohol", "Intended to reduce crime and poverty; enforced by the Volstead Act", "Led to bootlegging, speakeasies, and organized crime (Al Capone)", "Widely violated; repealed by the 21st Amendment in 1933"] },
  { id: 12, cat: "CIVIL WAR ERA", term: "Dred Scott Decision", bullets: ["1857: enslaved man Dred Scott sued for freedom after living in a free state", "Chief Justice Taney ruled enslaved people are property, not citizens — cannot sue", "Also struck down the Missouri Compromise, opening all territories to slavery", "Dramatically deepened sectional tensions heading into the Civil War"] },
  { id: 13, cat: "PROG. ERA", term: "Monroe Doctrine", bullets: ["1823: declared the Western Hemisphere closed to further European colonization", "US would treat any European intervention in the Americas as a direct threat", "Extended by Roosevelt Corollary (1904) to justify US military intervention in Latin America", "Foundational to US foreign policy for over a century"] },
  { id: 14, cat: "GILDED AGE", term: "Laissez-Faire", bullets: ["French for 'let it be' — government should not interfere in the economy", "Favored by Gilded Age industrialists; justified by Social Darwinism", "Opposed by Progressives demanding regulation of big business", "Largely abandoned during the Great Depression when FDR's New Deal expanded government's role"] },
  { id: 15, cat: "FOUNDING", term: "Louisiana Purchase", bullets: ["1803: US purchased ~828,000 sq. miles of territory from France for $15 million", "Doubled the size of the United States overnight", "Jefferson questioned constitutionality — no explicit power to buy territory", "Led to Lewis & Clark Expedition and opened the door to westward expansion"] },
  { id: 16, cat: "CIVIL RIGHTS", term: "Harlem Renaissance", bullets: ["Cultural movement of the 1920s centered in Harlem, New York City", "Flowering of African American art, poetry, music (jazz, blues), and literature", "Key figures: Langston Hughes, Zora Neale Hurston, Duke Ellington, Louis Armstrong", "Challenged racial stereotypes and powerfully asserted Black cultural pride"] },
  { id: 17, cat: "PROG. ERA", term: "League of Nations", bullets: ["International peacekeeping org proposed by Wilson after WWI (his 14 Points)", "US Senate rejected the Treaty of Versailles — US never joined, fatally weakening it", "Unable to stop Hitler, Mussolini, and Japan's expansion in the 1930s", "Failed to prevent WWII; replaced by the United Nations in 1945"] },
  { id: 18, cat: "PROG. ERA", term: "Muckraker", bullets: ["Progressive Era journalists who exposed corruption, unsafe conditions, and injustice", "Upton Sinclair's The Jungle (1906) exposed horrific meatpacking plant conditions", "Ida Tarbell exposed Standard Oil's corrupt monopolistic practices", "Their work sparked public outrage that directly led to new government regulations"] },
  { id: 19, cat: "PROG. ERA", term: "Spanish-American War", bullets: ["1898 war between the US and Spain, driven by support for Cuban independence", "Fueled by the USS Maine explosion in Havana harbor and 'yellow journalism'", "US defeated Spain; gained Guam, Puerto Rico, and the Philippines", "Marked the US's emergence as an imperial power with overseas territories"] },
  { id: 20, cat: "PROG. ERA", term: "Imperialism", bullets: ["Policy of extending a nation's power over other territories", "US acquired overseas territories after the Spanish-American War (1898)", "Justified by Social Darwinism and desire for markets, resources, and naval bases", "Opposed by Anti-Imperialists like Mark Twain and Andrew Carnegie"] },

  // ── DAY 2 ────────────────────────────────────────────────────────────
  { id: 21, cat: "GREAT DEPRESSION", term: "New Deal", bullets: ["FDR's broad program to fight the Great Depression (1933–1939)", "Three goals: Relief (aid to Americans), Recovery (restart economy), Reform (prevent future crises)", "Created Social Security, FDIC, SEC, CCC, WPA, and other landmark programs", "Dramatically expanded the federal government's role in managing the economy"] },
  { id: 22, cat: "GREAT DEPRESSION", term: "Great Depression", bullets: ["Worst economic crisis in US history; triggered by the stock market crash of October 1929", "Unemployment hit 25%; banks failed, farms collapsed, millions became homeless", "The Dust Bowl and Hoover's ineffective response made conditions far worse", "Ended because WWII's industrial demands restored full employment"] },
  { id: 23, cat: "GILDED AGE", term: "Interstate Commerce", bullets: ["Trade and business activity that crosses state borders; regulated by the federal government", "Grounded in the Commerce Clause of the Constitution (Article I, Section 8)", "Interstate Commerce Act (1887): first federal law regulating railroads", "Foundation for much of Congress's authority to regulate American business"] },
  { id: 24, cat: "GILDED AGE", term: "Tariff", bullets: ["A tax on imported goods to protect domestic industries from foreign competition", "Smoot-Hawley Tariff (1930) triggered trade wars that deepened the Great Depression", "Major divide: North (pro-tariff) vs. South (anti-tariff) throughout the 1800s", "Also the primary source of federal revenue before the income tax existed"] },
  { id: 25, cat: "GREAT DEPRESSION", term: "Federal Reserve System", bullets: ["The central banking system of the United States, created by Congress in 1913", "Controls money supply and sets interest rates to manage inflation and unemployment", "Acts as a 'lender of last resort' to prevent bank panics", "Divided into 12 regional banks overseen by a Board of Governors"] },
  { id: 26, cat: "CIVIL WAR ERA", term: "Reconstruction", bullets: ["Federal program (1865–1877) to rebuild the South after the Civil War", "13th Amendment abolished slavery; 14th granted citizenship; 15th gave Black men the vote", "Freedmen briefly gained political rights and held elected office", "Ended with Compromise of 1877; Jim Crow laws immediately reversed most gains"] },
  { id: 27, cat: "GILDED AGE", term: "Trusts", bullets: ["Massive business combinations merging companies to control entire industries", "Eliminated competition; monopolies set prices and exploited consumers (Standard Oil, US Steel)", "Targeted by the Sherman Antitrust Act (1890) and Roosevelt's trust-busting", "Symbol of Gilded Age excess — concentrated enormous wealth in very few hands"] },
  { id: 28, cat: "CIVIL WAR ERA", term: "Jim Crow", bullets: ["State and local laws enforcing racial segregation in the South after Reconstruction", "'Separate but equal' upheld as constitutional in Plessy v. Ferguson (1896)", "Enforced segregation in schools, transportation, restaurants, and all public spaces", "Dismantled by the Civil Rights Act (1964) and Voting Rights Act (1965)"] },
  { id: 29, cat: "PROG. ERA", term: "Schenck v. US", bullets: ["1919 Supreme Court case testing First Amendment limits during wartime", "Schenck convicted for anti-draft pamphlets that violated the Espionage Act", "Justice Holmes ruled speech can be limited if it presents a 'clear and present danger'", "Famous analogy: 'falsely shouting fire in a crowded theatre'"] },
  { id: 30, cat: "CIVIL WAR ERA", term: "14th Amendment", bullets: ["Ratified in 1868 following the Civil War", "Granted citizenship to all born or naturalized in the US — directly overturned Dred Scott", "Guaranteed equal protection under the law and due process to all citizens", "Legal foundation for virtually every major civil rights ruling in US history"] },
  { id: 31, cat: "FOUNDING", term: "Elastic Clause", bullets: ["Article I, Section 8: Congress can make laws 'necessary and proper' to carry out its powers", "Allows Congress to stretch beyond what's explicitly written — source of all 'implied powers'", "Used by Hamilton to justify a national bank; upheld in McCulloch v. Maryland (1819)", "Key reason the federal government's authority has expanded dramatically over time"] },
  { id: 32, cat: "FOUNDING", term: "Unwritten Constitution", bullets: ["Customs and practices not in the Constitution but governing how the country operates", "Examples: Washington's two-term precedent, the Cabinet, political parties, judicial review", "Fills gaps where the written Constitution is silent", "Shows government evolves through custom and tradition, not just formal amendments"] },
  { id: 33, cat: "GILDED AGE", term: "Sherman Antitrust Act", bullets: ["1890 — first major federal law prohibiting monopolies and restraint of trade", "Made it illegal for businesses to combine in ways that eliminate competition", "Initially underenforced; Theodore Roosevelt used it aggressively to break up trusts", "Foundation of American antitrust law; still enforced today"] },
  { id: 34, cat: "GILDED AGE", term: "Social Darwinism", bullets: ["Applied Darwin's 'survival of the fittest' to human society and the economy", "Argued the wealthy are naturally superior; poverty is the result of natural weakness", "Justified laissez-faire capitalism and opposition to government aid for the poor", "Also used to justify imperialism and racism; hugely influential among Gilded Age elites"] },
  { id: 35, cat: "FOUNDING", term: "Alien & Sedition Acts", bullets: ["Four laws under President John Adams in 1798, during tensions with France", "Made it illegal to criticize the federal government; tightened immigration requirements", "Targeted Jeffersonian opponents; widely seen as unconstitutional", "Sparked Virginia and Kentucky Resolutions asserting states' right to nullify federal laws"] },
  { id: 36, cat: "GREAT DEPRESSION", term: "Dust Bowl", bullets: ["1930s catastrophe in the Great Plains — drought + poor farming = massive dust storms", "'Black blizzard' storms destroyed crops and buried entire communities", "Forced 3.5 million+ 'Okies' to flee, mostly to California", "Deepened the Great Depression; led to major federal soil conservation programs"] },
  { id: 37, cat: "FOUNDING", term: "Mayflower Compact", bullets: ["1620 agreement signed by Pilgrims before landing at Plymouth", "First example of self-governance and majority-rule democracy in colonial America", "Established that government derives authority from the consent of the governed", "An important early precedent for American democratic values"] },
  { id: 38, cat: "FOUNDING", term: "Mercantilism", bullets: ["Economic theory: colonies exist to supply raw materials and buy manufactured goods from the mother country", "Britain enforced it through Navigation Acts, tightly restricting colonial trade", "Goal: accumulate gold and maintain a favorable trade balance", "Colonial resentment of these restrictions was a key economic cause of the Revolution"] },
  { id: 39, cat: "PROG. ERA", term: "Referendum", bullets: ["Citizens vote directly on a proposed law or policy, bypassing the legislature", "Part of the Progressive Era push for more direct democracy", "Paired with initiative (citizens propose laws) and recall (citizens remove officials)", "Still widely used in US states today as a check on legislative power"] },
  { id: 120, cat: "CIVIL WAR ERA", term: "Plessy v. Ferguson", bullets: [
    "1896 Supreme Court case that upheld racial segregation as constitutional",
    "Established the 'separate but equal' doctrine — the legal basis for Jim Crow laws",
    "Homer Plessy, a Black man, was arrested for sitting in a whites-only railroad car",
    "Overturned by Brown v. Board of Education in 1954 — one of the most consequential reversals in SC history"
  ] },

  // ── WWII ─────────────────────────────────────────────────────────────
  { id: 40, cat: "WWII", term: "Allied Powers", bullets: ["Main anti-Axis alliance: United States, Britain, Soviet Union, France, and China", "US joined officially after Japan's attack on Pearl Harbor, December 1941", "Coordinated strategy at Tehran (1943), Yalta (Feb. 1945), and Potsdam (July 1945)", "Won WWII and shaped the postwar world, including the founding of the United Nations"] },
  { id: 41, cat: "WWII", term: "Axis Powers", bullets: ["Germany, Italy, and Japan — allied through the Tripartite Pact (September 1940)", "Led by Hitler (Germany), Mussolini (Italy), and Hirohito/Tojo (Japan)", "Aggressive, expansionist powers whose invasions directly triggered WWII", "All three defeated by 1945: Germany surrendered May; Japan surrendered September"] },
  { id: 42, cat: "WWII", term: "Dwight Eisenhower", bullets: ["Supreme Commander of Allied Forces in Europe during WWII", "Planned and commanded D-Day — the Allied invasion of Normandy (June 6, 1944)", "Later became the 34th President of the United States (1953–1961)", "In his farewell address, warned of the growing 'military-industrial complex'"] },
  { id: 43, cat: "WWII", term: "Douglas MacArthur", bullets: ["US Army General commanding Allied forces in the Pacific theater", "Forced out of Philippines in 1942, vowed 'I shall return' — fulfilled in 1944", "Developed the 'island hopping' strategy to advance toward Japan", "Accepted Japan's surrender (Sept. 2, 1945); later fired by Truman during the Korean War"] },
  { id: 44, cat: "WWII", term: "Harry S Truman", bullets: ["FDR's VP; became President upon FDR's death in April 1945", "Ordered atomic bombs dropped on Hiroshima (Aug. 6) and Nagasaki (Aug. 9), ending WWII", "Launched the Marshall Plan and Truman Doctrine to contain Soviet expansion", "Desegregated the US military by Executive Order 9981 in 1948"] },
  { id: 45, cat: "WWII", term: "Winston Churchill", bullets: ["British Prime Minister who led the UK through WWII", "Rallied British morale with powerful speeches ('We shall fight on the beaches…')", "Co-signed the Atlantic Charter with FDR (1941) outlining postwar democratic principles", "Voted out of office in July 1945 — before Japan's formal surrender in September"] },
  { id: 46, cat: "WWII", term: "Joseph Stalin", bullets: ["Soviet dictator who signed the Nazi-Soviet Non-Aggression Pact with Hitler in 1939", "Joined the Allies after Germany invaded the USSR in June 1941", "Attended all major Allied conferences: Tehran, Yalta, and Potsdam", "Used the postwar settlement to impose Soviet control over Eastern Europe"] },
  { id: 47, cat: "WWII", term: "Robert Oppenheimer", bullets: ["Physicist who directed the Manhattan Project at Los Alamos, New Mexico", "Known as the 'father of the atomic bomb'", "After the Trinity test, quoted: 'Now I am become Death, the destroyer of worlds'", "Opposed the hydrogen bomb after the war; lost security clearance during the Red Scare (1954)"] },
  { id: 48, cat: "WWII", term: "The Manhattan Project", bullets: ["Top-secret US program to develop the world's first atomic bomb (1942–1945)", "Directed by Oppenheimer at Los Alamos; involved thousands of scientists", "Successfully tested with the 'Trinity' explosion in New Mexico, July 16, 1945", "Led to bombs on Hiroshima and Nagasaki — ended WWII and launched the nuclear age"] },
  { id: 49, cat: "WWII", term: "September 1, 1939", bullets: ["Germany invaded Poland — the official start of WWII in Europe", "Hitler used Blitzkrieg ('lightning war'): fast combined air and ground assault", "Britain and France declared war on Germany two days later, September 3", "US remained officially neutral but began aiding Britain through 'Cash & Carry'"] },
  { id: 50, cat: "WWII", term: "December 7, 1941", bullets: ["Japan launched a surprise aerial attack on US naval base at Pearl Harbor, Hawaii", "~2,400 Americans killed; 8 battleships damaged or sunk, hundreds of aircraft destroyed", "FDR called it 'a date which will live in infamy' — Congress declared war on Japan next day", "Germany and Italy declared war on the US days later, fully pulling America into WWII"] },
  { id: 51, cat: "WWII", term: "Munich Conference", bullets: ["September 1938: Britain and France appeased Hitler, allowing him to annex the Sudetenland", "Chamberlain declared 'peace for our time' — Hitler invaded the rest of Czechoslovakia months later", "The textbook example of the failure of the policy of appeasement", "Showed that conceding territory to aggressors only encourages further aggression"] },
  { id: 52, cat: "WWII", term: "'Cash & Carry'", bullets: ["1939 US neutrality policy: nations could buy US weapons if they paid cash and transported them", "Heavily favored Britain, which had the naval power to carry goods across the Atlantic", "Allowed the US to aid Allies financially while technically remaining neutral", "Replaced by the more generous Lend-Lease Act in March 1941"] },
  { id: 53, cat: "WWII", term: "Lend-Lease Act", bullets: ["1941 law allowing the US to lend or lease weapons to any nation vital to US defense", "Provided ~$50 billion in aid to Britain, USSR, China, France, and others", "Effectively ended US neutrality — America was clearly supporting the Allied cause", "Made the US the 'Arsenal of Democracy' before officially entering the war"] },
  { id: 54, cat: "WWII", term: "'Island Hopping'", bullets: ["US Pacific strategy developed by MacArthur and Admiral Nimitz", "Bypassed heavily fortified Japanese islands; captured only strategically vital ones for air bases", "Cut Japanese supply lines, moving progressively closer to Japan", "Key campaigns: Guadalcanal (1942–43), Philippines (1944), Iwo Jima and Okinawa (1945)"] },
  { id: 55, cat: "WWII", term: "Battle of Midway", bullets: ["Pivotal Pacific naval battle, June 1942 — fought entirely by carrier-based aircraft", "US cracked Japanese codes, giving advance knowledge of the attack plan", "US sank 4 Japanese aircraft carriers and killed hundreds of elite Japanese pilots", "Decisive turning point — Japan lost naval air superiority and never recovered it"] },
  { id: 56, cat: "WWII", term: "June 6, 1944 — D-Day", bullets: ["Allied amphibious invasion of Normandy, France — the largest seaborne invasion in history", "Commanded by Eisenhower; over 150,000 Allied troops landed on five beaches in one day", "Opened a critical second front, forcing Germany to fight east and west simultaneously", "Decisive turning point in Europe; liberation of Western Europe quickly followed"] },
  { id: 57, cat: "WWII", term: "V-E Day", bullets: ["May 8, 1945 — Germany surrendered unconditionally to the Allied Powers", "Hitler committed suicide in his Berlin bunker on April 30, 1945", "Triggered massive celebrations across the US, UK, and liberated Europe", "The war in the Pacific continued for three more months"] },
  { id: 58, cat: "WWII", term: "V-J Day", bullets: ["August 15, 1945 — Japan announced its surrender after the atomic bombings", "Formal surrender signed September 2, 1945, aboard USS Missouri in Tokyo Bay", "Ended World War II completely — the deadliest conflict in human history", "Followed by US occupation of Japan under MacArthur's oversight"] },
  { id: 59, cat: "WWII", term: "Bataan Death March", bullets: ["April 1942: ~76,000 American and Filipino POWs forced to march 65+ miles after the Philippines fell", "Extreme heat, no food or water, beatings, and executions killed thousands along the route", "Survivors held in brutal Japanese prison camps where thousands more died", "A major war crime that intensified American resolve to defeat Japan"] },
  { id: 60, cat: "WWII", term: "Battle of the Bulge", bullets: ["December 1944 – January 1945: Germany's last major offensive on the Western Front", "Surprise attack pushed a deep 'bulge' into Allied lines in Belgium's Ardennes forest", "Americans held Bastogne ('Nuts!' — McAuliffe's famous reply to German surrender demands)", "Germany exhausted its last reserves; the end of the war in Europe accelerated"] },
  { id: 61, cat: "WWII", term: "Hiroshima & Nagasaki", bullets: ["US dropped atomic bombs: Hiroshima August 6; Nagasaki August 9, 1945", "Estimated 130,000–226,000 killed immediately and from radiation exposure", "Japan surrendered August 15; Truman argued bombs saved lives by avoiding a land invasion", "Launched the nuclear age and directly triggered the Cold War arms race"] },
  { id: 62, cat: "WWII", term: "War Production Board", bullets: ["Federal agency (1942) coordinating conversion of US industry to wartime production", "Factories switched from consumer goods to tanks, planes, ships, and weapons", "US became the 'Arsenal of Democracy,' out-producing all Axis nations combined", "Transformed the American economy and definitively ended the Great Depression"] },
  { id: 63, cat: "WWII", term: "War Labor Board", bullets: ["Mediated disputes between workers and management during WWII", "Primary goal: prevent strikes that would disrupt essential wartime production", "Stabilized wages and maintained labor peace throughout the war", "Balanced workers' needs with the national urgency of maximum war output"] },
  { id: 64, cat: "WWII", term: "Office of Price Administration", bullets: ["Federal agency (OPA) created 1941 to control prices and manage rationing on the home front", "Set price ceilings on consumer goods to prevent wartime inflation", "Issued ration books limiting civilian access to scarce goods: gas, meat, sugar, rubber", "Ended after the war; prices rose sharply once controls were lifted"] },
  { id: 65, cat: "WWII", term: "Executive Order 9066", bullets: ["Signed by FDR in February 1942 — authorized forced removal of Japanese Americans from the West Coast", "~120,000 people of Japanese descent (2/3 were US citizens) were sent to internment camps", "Justified by military necessity after Pearl Harbor; widely condemned as racist", "In 1988 the US formally apologized and paid $20,000 reparations to surviving internees"] },
  { id: 66, cat: "WWII", term: "Korematsu v. US (1944)", bullets: ["Supreme Court case challenging the constitutionality of Japanese American internment", "Fred Korematsu refused to report to an internment camp and sued the government", "Court ruled 6–3 that military necessity justified suspending civil liberties", "One of the most condemned SC decisions in history; formally overturned in 2018"] },
  { id: 67, cat: "WWII", term: "War Bonds", bullets: ["Government bonds sold to American citizens to help finance WWII", "Citizens lent money to the government, repaid with interest after the war", "Promoted through massive campaigns featuring celebrities and patriotic posters", "Raised over $185 billion; also fought inflation by pulling spending money out of the economy"] },
  { id: 68, cat: "WWII", term: "Victory Gardens", bullets: ["Vegetable gardens planted by civilians at home (backyards, parks, empty lots) during WWII", "Reduced pressure on commercial food production, freeing it for the military", "Over 20 million gardens planted across the United States", "Symbolized civilian sacrifice, patriotism, and the home front contribution to the war effort"] },
  { id: 69, cat: "WWII", term: "'Rosie the Riveter'", bullets: ["Symbol of millions of women who entered the industrial workforce during WWII", "~6 million women took factory, shipyard, and defense industry jobs while men were at war", "The 'We Can Do It!' poster depicted women as strong, capable, and essential to the war effort", "Challenged traditional gender roles — though many were pushed out after men returned"] },
  { id: 70, cat: "WWII", term: "Rationing", bullets: ["Government system fairly distributing scarce goods to civilians during WWII", "Items rationed included gasoline, meat, butter, sugar, rubber, coffee, and shoes", "Ration books issued to all households — rationed goods couldn't be bought without stamps", "Managed by the OPA; required real sacrifice and cooperation from all Americans"] },
  { id: 71, cat: "WWII", term: "Holocaust", bullets: ["Nazi Germany's systematic genocide: 6 million Jews + ~5 million others murdered", "Hitler's 'Final Solution' used concentration and extermination camps (Auschwitz, Treblinka)", "Began with Nuremberg Laws (1935) stripping Jews of rights; mass murder escalated after 1941", "Allied forces liberated the camps 1944–1945, exposing the full horror to the entire world"] },
  { id: 72, cat: "WWII", term: "Nuremberg Trials", bullets: ["1945–1946: International tribunal tried top Nazi leaders for war crimes", "Established that 'following orders' is NOT a valid defense for committing atrocities", "Defined crimes against humanity, crimes against peace, and war crimes as legal categories", "12 sentenced to death; set precedent that later led to the International Criminal Court (ICC)"] },

  // ── REVOLUTIONARY ERA ──────────────────────────────────────────────────
  { id: 73, cat: "REV. ERA", term: "Declaration of Independence", bullets: ["Written by Thomas Jefferson in 1776; formally announced the colonies' break from Britain", "Based on Enlightenment ideas: natural rights (life, liberty, pursuit of happiness), consent of the governed", "Argued that when a government fails to protect rights, the people have the right to overthrow it", "Directly influenced by John Locke's social contract theory"] },
  { id: 74, cat: "REV. ERA", term: "Common Sense", bullets: ["1776 pamphlet by Thomas Paine arguing powerfully for American independence", "Written in plain language so ordinary colonists — not just elites — could understand it", "Argued it was absurd for a large continent to be governed by a small island (Britain)", "Shifted colonial public opinion dramatically toward supporting independence"] },
  { id: 75, cat: "REV. ERA", term: "Boston Massacre", bullets: ["March 5, 1770: British soldiers fired into a crowd of colonists in Boston, killing 5", "Paul Revere's engraving of the event was used as anti-British propaganda by Patriots", "Heightened colonial anger at British military presence in American cities", "One of several events that pushed colonists steadily toward revolution"] },
  { id: 76, cat: "REV. ERA", term: "Shays' Rebellion", bullets: ["1786–1787: armed uprising by Massachusetts farmers unable to pay their debts", "Exposed the fatal weakness of the Articles of Confederation — the government couldn't suppress it", "Alarmed leaders like Washington and Hamilton about the desperate need for a stronger central government", "Directly triggered the Constitutional Convention of 1787"] },
  { id: 77, cat: "REV. ERA", term: "Stamp Act", bullets: ["1765 British law taxing all printed materials in the colonies (newspapers, legal documents, etc.)", "First direct tax Parliament imposed on the colonists without their consent", "Sparked the rallying cry 'No taxation without representation'", "Led to the Stamp Act Congress — the first coordinated colonial protest against British taxation"] },
  { id: 78, cat: "REV. ERA", term: "Federalists vs. Anti-Federalists", bullets: ["Federalists (Hamilton, Madison, Jay): supported strong central government; wrote the Federalist Papers", "Anti-Federalists (Patrick Henry, George Mason): feared a powerful central government would crush states' rights", "Anti-Federalists demanded a Bill of Rights as a condition of ratifying the Constitution", "The debate shaped the final Constitution and directly led to the first 10 amendments"] },
  { id: 79, cat: "REV. ERA", term: "Declaration of Sentiments", bullets: ["1848 document written at the Seneca Falls Convention by Elizabeth Cady Stanton", "Modeled on the Declaration of Independence: 'all men AND women are created equal'", "Demanded voting rights, property rights, and equal legal standing for women", "Launched the organized women's suffrage movement in the United States"] },
  { id: 80, cat: "REV. ERA", term: "Washington's Farewell Address", bullets: ["1796: Washington's final address advising the nation on its future direction", "Warned against permanent alliances with foreign nations — established the tradition of isolationism", "Warned against the dangers of political parties creating destructive factionalism", "Set the voluntary two-term presidential precedent that lasted until FDR (1940)"] },
  { id: 81, cat: "REV. ERA", term: "McCulloch v. Maryland", bullets: ["1819: Maryland tried to tax the federally chartered Bank of the United States", "Chief Justice Marshall ruled: states cannot tax federal institutions — federal law is supreme", "Upheld implied powers under the Elastic Clause; Congress can create a national bank", "Dramatically expanded federal power and established the principle of federal supremacy"] },
  { id: 82, cat: "REV. ERA", term: "Strict vs. Loose Construction", bullets: ["Strict construction (Jefferson): government can ONLY do what the Constitution explicitly states", "Loose construction (Hamilton): government can do anything the Constitution doesn't explicitly forbid", "The debate centered on whether Congress could legally create a national bank", "This fundamental disagreement led to the formation of America's first two political parties"] },
  { id: 83, cat: "REV. ERA", term: "Natural Rights / Social Contract", bullets: ["John Locke's Enlightenment philosophy: all people are born with natural rights — life, liberty, and property", "Government is a social contract: people surrender some freedoms in exchange for protection of their rights", "If government breaks the contract by denying natural rights, the people have the right to revolt", "Directly influenced the Declaration of Independence and the entire framework of American government"] },
  { id: 84, cat: "REV. ERA", term: "Virginia House of Burgesses", bullets: ["1619: First representative legislative assembly in colonial America, established in Virginia", "Colonists elected representatives to create their own laws — an early model of democratic self-governance", "Established the precedent that colonists had the right to govern themselves", "A foundational democratic tradition that eventually led to the American Revolution"] },

  // ── PROGRESSIVE ERA / WWI ────────────────────────────────────────────
  { id: 85, cat: "PROG. ERA", term: "Progressive Era", bullets: ["Reform movement (1890s–1920s) responding to problems of industrialization, urbanization, and corruption", "Sought to use government power to regulate big business, protect workers, and improve society", "Key reforms: antitrust enforcement, Pure Food and Drug Act, women's suffrage, direct election of senators", "Presidents: Theodore Roosevelt, William Howard Taft, and Woodrow Wilson"] },
  { id: 86, cat: "PROG. ERA", term: "Theodore Roosevelt", bullets: ["26th President (1901–1909); known as the 'trust-buster' for aggressively breaking up monopolies", "Used the Sherman Antitrust Act to break up Standard Oil and the Northern Securities Company", "Championed the Pure Food and Drug Act (1906) and expanded the national park system dramatically", "Believed government had a duty to regulate the economy for the public good — 'Square Deal'"] },
  { id: 87, cat: "PROG. ERA", term: "Pure Food and Drug Act", bullets: ["1906 federal law prohibiting the manufacture and sale of adulterated or mislabeled food and drugs", "Passed largely as a direct response to Upton Sinclair's The Jungle exposing meatpacking conditions", "Created the foundation for the modern Food and Drug Administration (FDA)", "A landmark example of Progressive Era government intervention to protect consumers"] },
  { id: 88, cat: "PROG. ERA", term: "Great Migration", bullets: ["Mass movement of approximately 6 million African Americans from the rural South to the urban North (1910–1970)", "Driven by escape from Jim Crow laws, racial violence (lynching), and lack of economic opportunity", "Transformed Northern cities like New York, Chicago, Detroit, and Philadelphia", "Fueled the growth of Black urban communities and cultural movements like the Harlem Renaissance"] },
  { id: 89, cat: "PROG. ERA", term: "WWI — US Entry", bullets: ["WWI began in Europe in 1914; US remained officially neutral under Wilson until 1917", "Zimmermann Telegram (1917): Germany proposed a military alliance with Mexico against the US", "Unrestricted German submarine warfare sank American ships, including the Lusitania (1,198 killed, 1915)", "US declared war on Germany in April 1917; drafted 3 million soldiers"] },
  { id: 90, cat: "PROG. ERA", term: "Zimmermann Telegram", bullets: ["1917: Secret German message to Mexico proposing a military alliance against the United States", "Germany promised Mexico help recovering Texas, New Mexico, and Arizona if the US entered WWI", "British intelligence intercepted and decoded it, then shared it with the US government", "Outraged American public opinion and directly helped push Congress to declare war on Germany"] },
  { id: 91, cat: "PROG. ERA", term: "Wilson's 14 Points", bullets: ["President Wilson's plan for a just and lasting peace after WWI (January 1918)", "Key points: freedom of the seas, self-determination for nations, no secret treaties, reduced armaments", "Point 14: creation of a League of Nations for collective international peacekeeping", "European Allies largely ignored the 14 Points at the Paris Peace Conference — focused on punishing Germany"] },
  { id: 92, cat: "PROG. ERA", term: "Treaty of Versailles", bullets: ["1919 peace treaty that officially ended WWI; signed at Versailles, France", "Harshly punished Germany: war guilt clause, $33 billion in reparations, military restrictions, territorial losses", "Created the League of Nations — but the US Senate refused to ratify it so the US never joined", "The brutal terms created economic despair in Germany, directly contributing to Hitler's rise and WWII"] },
  { id: 93, cat: "PROG. ERA", term: "Isolationism", bullets: ["US foreign policy of avoiding involvement in European conflicts, alliances, and wars", "Rooted in Washington's Farewell Address (1796) warning against 'entangling alliances'", "Dominant US policy in the 1930s as Europe and Asia descended toward war", "Ended permanently after Pearl Harbor (December 7, 1941) — the US was forced into WWII"] },
  { id: 94, cat: "PROG. ERA", term: "Big Stick / Dollar Diplomacy", bullets: ["Big Stick Policy (TR): use military force if needed to protect US interests in Latin America", "Roosevelt Corollary (1904): the US has the right to intervene in Latin American nations unable to manage their affairs", "Dollar Diplomacy (Taft): use American economic investment and loans to extend US influence abroad", "Both represented extensions of US imperialism and the Monroe Doctrine in the Western Hemisphere"] },

  // ── COLD WAR ─────────────────────────────────────────────────────────
  { id: 95, cat: "COLD WAR", term: "Containment Policy", bullets: ["US foreign policy strategy to prevent the spread of Soviet communism after WWII", "Articulated by diplomat George Kennan (1946); became the basis of all Cold War US foreign policy", "The US would not try to remove existing communism, but would prevent it from spreading to new countries", "Led to the Truman Doctrine, Marshall Plan, NATO, Korean War, and Vietnam War"] },
  { id: 96, cat: "COLD WAR", term: "Truman Doctrine", bullets: ["1947: Truman pledged US political, military, and economic support to any nation threatened by communism", "Announced in response to communist threats against Greece and Turkey", "Marked a decisive shift from US isolationism to active global engagement", "First concrete application of the containment policy — a defining moment of the Cold War"] },
  { id: 97, cat: "COLD WAR", term: "Marshall Plan", bullets: ["1948: US economic program providing $13 billion to rebuild war-devastated Western European nations", "Goal: prevent economically desperate European countries from turning to communism", "Enormously successful — rebuilt Western Europe and created strong, democratic, pro-American allies", "The Soviet Union refused to participate and forced Eastern European nations to reject it as well"] },
  { id: 98, cat: "COLD WAR", term: "NATO", bullets: ["North Atlantic Treaty Organization (1949): military alliance between the US, Canada, and Western Europe", "'An attack on one member is an attack on all' — collective defense against Soviet aggression", "Created specifically to deter a Soviet invasion of Western Europe during the Cold War", "Still exists today; expanded after the Cold War to include many former Soviet bloc nations"] },
  { id: 99, cat: "COLD WAR", term: "Iron Curtain", bullets: ["Term coined by Winston Churchill (1946) describing the division of Europe between the democratic West and communist East", "Soviet-controlled Eastern European nations were politically and economically sealed off from the West", "Physically symbolized by the Berlin Wall (built 1961), dividing communist East Berlin from democratic West Berlin", "The Iron Curtain fell in 1989–1991 as communist governments collapsed across Eastern Europe"] },
  { id: 100, cat: "COLD WAR", term: "Korean War", bullets: ["1950–1953: North Korea (communist) invaded South Korea (democratic), starting the first 'hot war' of the Cold War", "UN forces led by the US (General MacArthur) pushed back the invasion; China then entered on North Korea's side", "Ended in a stalemate at the 38th parallel — the exact same dividing line as before the war", "MacArthur was fired by Truman for publicly defying presidential authority on war strategy"] },
  { id: 101, cat: "COLD WAR", term: "McCarthyism", bullets: ["Senator Joseph McCarthy led aggressive, often baseless accusations of communist infiltration in US government", "Created a nationwide climate of fear, suspicion, and political persecution in the early 1950s", "Thousands of Americans lost jobs or were blacklisted based on unproven accusations — 'witch hunts'", "McCarthy was censured by the Senate in 1954; his name became synonymous with reckless political persecution"] },
  { id: 102, cat: "COLD WAR", term: "Cuban Missile Crisis", bullets: ["October 1962: 13-day standoff after the US discovered Soviet nuclear missiles being installed in Cuba", "President Kennedy imposed a naval blockade of Cuba; the world stood at the brink of nuclear war", "Resolved when the Soviets agreed to remove the missiles; US secretly agreed to remove missiles from Turkey", "The closest the Cold War ever came to nuclear war; led to the creation of a US-Soviet hotline"] },
  { id: 103, cat: "COLD WAR", term: "Arms Race & Space Race", bullets: ["US and USSR competed throughout the Cold War to build more powerful nuclear weapons and delivery systems", "Space Race: Soviets launched Sputnik (1957) — first satellite; US landed on the moon (1969, Apollo 11)", "Both races driven by fear, national prestige, and the desire to demonstrate technological superiority", "Arms race produced the doctrine of MAD (Mutually Assured Destruction) — nuclear war means total annihilation for both sides"] },
  { id: 104, cat: "COLD WAR", term: "Berlin Wall", bullets: ["Built in 1961 by East Germany (with Soviet backing) to stop East Germans from fleeing to the democratic West", "Became the most powerful physical symbol of Cold War division and communist oppression", "President Kennedy visited West Berlin (1963): 'Ich bin ein Berliner' — expressing American solidarity", "The Wall fell November 9, 1989, symbolizing the collapse of communism and the end of the Cold War"] },
  { id: 105, cat: "COLD WAR", term: "Détente", bullets: ["1970s policy of relaxing Cold War tensions between the US and Soviet Union, primarily under President Nixon", "Led to SALT I (1972) arms control agreement limiting nuclear weapons stockpiles", "Nixon's historic visit to China (1972) opened diplomatic relations after 25 years of hostility", "Represented a shift from direct confrontation to negotiation and coexistence"] },
  { id: 106, cat: "COLD WAR", term: "Domino Theory", bullets: ["Cold War belief that if one country fell to communism, neighboring countries would follow like falling dominoes", "First articulated by President Eisenhower in 1954 regarding Southeast Asia", "Used to justify US military involvement in Korea, Vietnam, and other conflicts around the world", "Guided US foreign policy for decades; its validity is still debated by historians"] },

  // ── CIVIL RIGHTS ─────────────────────────────────────────────────────
  { id: 107, cat: "CIVIL RIGHTS", term: "Brown v. Board of Education", bullets: ["1954: Supreme Court unanimously ruled that racial segregation in public schools is unconstitutional", "Directly overturned the 'separate but equal' doctrine from Plessy v. Ferguson (1896)", "Chief Justice Earl Warren wrote the unanimous opinion — a landmark moment in legal history", "Sparked and energized the modern Civil Rights Movement by proving the courts could be an ally"] },
  { id: 108, cat: "CIVIL RIGHTS", term: "Montgomery Bus Boycott", bullets: ["1955–1956: Rosa Parks refused to give up her bus seat in Montgomery, Alabama — was arrested", "The Black community boycotted the city's bus system for 381 days, causing significant financial damage", "Led by a young Dr. Martin Luther King Jr., making him a national figure", "The Supreme Court ultimately ruled Montgomery's bus segregation unconstitutional — a major victory"] },
  { id: 109, cat: "CIVIL RIGHTS", term: "Martin Luther King Jr.", bullets: ["Leader of the Civil Rights Movement; advocated nonviolent protest and civil disobedience inspired by Gandhi", "Led the Montgomery Bus Boycott, Birmingham Campaign, and March on Washington (1963)", "'I Have a Dream' speech (1963) powerfully articulated the vision of racial equality and integration", "Assassinated April 4, 1968; awarded the Nobel Peace Prize in 1964"] },
  { id: 110, cat: "CIVIL RIGHTS", term: "Civil Rights Act (1964)", bullets: ["Landmark federal law signed by President Lyndon Johnson banning discrimination based on race, color, religion, sex, or national origin", "Outlawed segregation in all public accommodations: restaurants, hotels, theaters, stores", "Prohibited employment discrimination — employers could no longer legally refuse to hire based on race", "One of the most transformative pieces of legislation in American history"] },
  { id: 111, cat: "CIVIL RIGHTS", term: "Voting Rights Act (1965)", bullets: ["Federal law that eliminated discriminatory voting practices designed to disenfranchise Black voters", "Banned literacy tests, poll taxes, and other devices used to prevent minorities from voting", "Authorized federal oversight of elections in states with proven histories of racial discrimination", "Black voter registration surged dramatically in the years following — a historic achievement of the movement"] },
  { id: 112, cat: "CIVIL RIGHTS", term: "Malcolm X & Black Power", bullets: ["Malcolm X: early advocate of Black nationalism and self-defense rather than integration — contrasted with MLK's nonviolence", "Represented a more militant wing of the Civil Rights Movement; later moderated his views; assassinated 1965", "Black Power movement (mid-1960s): emphasized Black pride, self-sufficiency, and political power over integration", "Reflected frustration that nonviolent protest was too slow to achieve real equality"] },
  { id: 113, cat: "CIVIL RIGHTS", term: "March on Washington", bullets: ["August 28, 1963: massive civil rights rally of ~250,000 people in Washington, D.C.", "Site of MLK's iconic 'I Have a Dream' speech, calling for racial equality and justice", "Demanded passage of civil rights legislation and an end to racial discrimination in employment", "One of the largest political demonstrations in US history; put enormous public pressure on Congress"] },
  { id: 114, cat: "CIVIL RIGHTS", term: "Nonviolent Protest / Civil Disobedience", bullets: ["Strategy of deliberately and peacefully breaking unjust laws to expose injustice and force change", "Inspired by Gandhi's successful nonviolent resistance movement in India", "Tactics used: sit-ins (Greensboro lunch counter, 1960), freedom rides, marches, and boycotts", "When peaceful protesters were met with violence, it generated national sympathy and political pressure for change"] },
  { id: 115, cat: "CIVIL RIGHTS", term: "Great Society", bullets: ["President Lyndon Johnson's sweeping domestic program (1964–1968) aimed at eliminating poverty and racial injustice", "Created Medicare and Medicaid (1965) providing healthcare for the elderly and the poor", "Signed the Civil Rights Act (1964) and Voting Rights Act (1965)", "The most ambitious expansion of the federal government's domestic role since FDR's New Deal"] },

  // ── KOREA / VIETNAM ──────────────────────────────────────────────────
  { id: 116, cat: "KOREA/VIETNAM", term: "Vietnam War", bullets: ["Conflict between communist North Vietnam (backed by USSR and China) and democratic South Vietnam (backed by US)", "US involvement escalated dramatically under President Johnson after the Gulf of Tonkin Resolution (1964)", "Massive anti-war movement at home deeply divided American society throughout the late 1960s", "US withdrew in 1973 (Paris Peace Accords); South Vietnam fell to communism in 1975 — a Cold War loss"] },
  { id: 117, cat: "KOREA/VIETNAM", term: "Gulf of Tonkin Resolution", bullets: ["1964: Congress gave President Johnson broad authority to use military force in Vietnam without a formal declaration of war", "Based on reports of North Vietnamese attacks on US ships — later found to be exaggerated or fabricated", "Allowed Johnson to escalate US involvement from ~16,000 advisors to over 500,000 combat troops", "Considered the key turning point that locked the US into full-scale involvement in Vietnam"] },
  { id: 118, cat: "KOREA/VIETNAM", term: "Ho Chi Minh", bullets: ["Leader of North Vietnam and the Viet Cong; Vietnamese communist and nationalist revolutionary", "Led Vietnamese resistance first against French colonialism, then against the US-backed South Vietnamese government", "Motivated by both communist ideology AND fierce Vietnamese nationalism — seen as a liberator by many Vietnamese", "His forces ultimately unified Vietnam under communist rule in 1975, two years after the US withdrew"] },
  { id: 119, cat: "KOREA/VIETNAM", term: "Anti-War Movement", bullets: ["Massive domestic opposition to the Vietnam War, especially on college campuses (late 1960s–early 1970s)", "Kent State (1970): National Guard killed 4 student protesters at Ohio's Kent State University — shocked the nation", "Pentagon Papers (1971): leaked classified documents revealed the government had been systematically lying about the war's progress", "The movement contributed to the US withdrawal from Vietnam and permanently changed how Americans view government and military authority"] },

  // ── MODERN ERA ───────────────────────────────────────────────────────
  { id: 121, cat: "MODERN ERA", term: "The Feminine Mystique", bullets: ["Betty Friedan's 1963 book challenged the idea that women found fulfillment solely as wives and mothers", "Described 'the problem that has no name' — widespread dissatisfaction among middle-class suburban housewives", "Sparked second-wave feminism and inspired millions of women to seek careers and equality beyond the home", "One of the most influential books of the 20th century; helped launch the modern women's liberation movement"] },
  { id: 122, cat: "MODERN ERA", term: "NOW (National Organization for Women)", bullets: ["Founded in 1966 by Betty Friedan and others to advocate for women's full equality in American society", "Pushed for equal pay, reproductive rights, accessible childcare, and an end to sex discrimination in all areas of life", "Lobbied for the Equal Rights Amendment (ERA), which passed Congress but fell 3 states short of ratification", "The largest feminist organization in the US; continues to advocate for women's rights today"] },
  { id: 123, cat: "MODERN ERA", term: "Equal Pay Act & Title IX", bullets: ["Equal Pay Act (1963): required equal pay for equal work regardless of gender — first major federal law addressing the gender pay gap", "Title IX (1972): prohibited sex discrimination in any educational program receiving federal funding", "Title IX dramatically expanded women's participation in sports — from 295,000 athletes in 1972 to millions today", "Both laws were products of the women's rights movement and remain central to gender equality enforcement"] },
  { id: 124, cat: "MODERN ERA", term: "Roe v. Wade", bullets: ["1973 Supreme Court ruling that women have a constitutional right to abortion, rooted in the right to privacy", "Based on the 14th Amendment's due process clause; extended the right to privacy established in Griswold v. Connecticut", "Divided the nation into pro-choice and pro-life camps — one of the most contested rulings in US history", "Overturned by Dobbs v. Jackson Women's Health Organization (2022), returning abortion regulation to individual states"] },
  { id: 125, cat: "MODERN ERA", term: "AIM (American Indian Movement)", bullets: ["Founded in 1968 to address police brutality, poverty, and federal violations of treaty rights against Native Americans", "Occupied Alcatraz Island (1969–1971) to demand return of federal land to Native peoples", "Led a 71-day standoff at Wounded Knee, South Dakota (1973) — drew national attention to Native American grievances", "Part of the broader Red Power movement; fought for tribal sovereignty and recognition of treaty rights"] },
  { id: 126, cat: "MODERN ERA", term: "Cesar Chavez & UFW", bullets: ["Cesar Chavez co-founded the United Farm Workers (UFW) in 1962 to organize migrant agricultural laborers", "Led the Delano Grape Strike (1965–1970) and called a national consumer boycott of table grapes", "Used nonviolent tactics — marches, hunger strikes, and boycotts — modeled on Gandhi and MLK", "Won improved wages and working conditions for farmworkers; became a symbol of the Latino civil rights movement"] },
  { id: 127, cat: "MODERN ERA", term: "ADA (Americans with Disabilities Act)", bullets: ["Landmark 1990 civil rights law prohibiting discrimination against people with disabilities in employment and public life", "Required employers to provide reasonable accommodations and mandated accessibility in public places and transportation", "Modeled on the Civil Rights Act of 1964 — extended those protections to over 50 million Americans with disabilities", "Led to physical changes across America: wheelchair ramps, accessible bathrooms, auditory pedestrian signals"] },
  { id: 128, cat: "MODERN ERA", term: "Rights of the Accused — Warren Court", bullets: ["Under Chief Justice Earl Warren (1953–1969), the Supreme Court dramatically expanded rights of criminal suspects", "Gideon v. Wainwright (1963): defendants have the right to an attorney even if they cannot afford one", "Mapp v. Ohio (1961): illegally obtained evidence cannot be used in court (exclusionary rule)", "Miranda v. Arizona (1966): police must inform suspects of their right to remain silent and right to counsel before interrogation"] },
  { id: 129, cat: "MODERN ERA", term: "Symbolic Speech", bullets: ["Supreme Court ruled that non-verbal expression — protests, art, and flag burning — is protected by the 1st Amendment", "Tinker v. Des Moines (1969): students wearing black armbands to protest the Vietnam War had protected free speech", "Texas v. Johnson (1989): burning the American flag is constitutionally protected symbolic speech", "The principle that 'speech' extends to meaningful expressive conduct is a cornerstone of First Amendment law"] },
  { id: 130, cat: "MODERN ERA", term: "Student Rights Cases", bullets: ["Series of Supreme Court rulings defining the scope of student rights within public schools", "Tinker v. Des Moines (1969): students do not 'shed their constitutional rights at the schoolhouse gate'", "New Jersey v. T.L.O. (1985): schools can search students based on 'reasonable suspicion,' not the stricter probable cause standard", "Hazelwood v. Kuhlmeier (1988): schools may regulate student newspapers if there is a legitimate educational reason"] },
  { id: 131, cat: "MODERN ERA", term: "Immigration Act of 1965", bullets: ["Abolished the national-origins quota system (1924 law) that heavily favored Northern and Western Europeans", "Created a new system prioritizing family reunification and skilled workers — equal treatment for all nationalities", "Dramatically changed US immigration — surge of newcomers from Latin America, Asia, Africa, and the Middle East", "Led to the most ethnically diverse wave of immigration in American history and reshaped US demographics"] },
  { id: 132, cat: "MODERN ERA", term: "Gay Rights & Stonewall", bullets: ["Stonewall Inn riots (June 1969): patrons of a NYC gay bar resisted a police raid — 6 nights of protests followed", "Widely considered the birth of the modern LGBTQ+ rights movement; galvanized gay Americans to organize politically", "Led to the first Pride marches (1970) and the formation of major LGBTQ+ advocacy organizations", "Movement grew for decades, culminating in marriage equality nationwide (Obergefell v. Hodges, 2015)"] },
  { id: 133, cat: "MODERN ERA", term: "Environmental Movement", bullets: ["Rachel Carson's Silent Spring (1962) exposed the dangers of DDT and sparked public awareness of pollution", "Earth Day (April 22, 1970): first mass environmental mobilization — 20 million participants across the US", "Nixon created the EPA and signed the Clean Air Act, Clean Water Act, and Endangered Species Act", "Marked a fundamental shift in US policy toward protecting natural resources and public health from industrial harm"] },
  { id: 134, cat: "MODERN ERA", term: "Watergate", bullets: ["1972: operatives linked to Nixon's reelection campaign broke into Democratic National Committee headquarters at the Watergate complex", "Nixon and aides orchestrated a cover-up — using the CIA and FBI to obstruct the investigation", "The 'smoking gun' tape proved Nixon obstructed justice; facing certain impeachment, he resigned August 9, 1974", "First presidential resignation in US history; deepened public distrust of government and led to campaign finance reform"] },
  { id: 135, cat: "MODERN ERA", term: "Détente & Nixon", bullets: ["Détente (French for 'relaxation'): Nixon's strategy of easing Cold War tensions through engagement and diplomacy", "Nixon's historic 1972 visit to China ended 25 years of hostility and opened diplomatic and trade relations", "SALT I (1972): Strategic Arms Limitation Treaty — first major nuclear arms control agreement between the US and USSR", "A pragmatic shift from Cold War confrontation to negotiation, engineered by Nixon and National Security Adviser Henry Kissinger"] },
  { id: 136, cat: "MODERN ERA", term: "Reaganomics", bullets: ["Reagan's economic policy based on supply-side economics (cutting taxes on the wealthy to stimulate investment)", "Cut the top marginal tax rate from 70% to 28%; reduced domestic social spending sharply", "Theory: tax cuts for business and the wealthy would 'trickle down' to workers — critics called it 'trickle-down economics'", "Supporters credit it with the 1980s economic expansion; critics say it widened income inequality and tripled the national debt"] },
  { id: 137, cat: "MODERN ERA", term: "Reagan & the New Right", bullets: ["Reagan's 1980 election marked the rise of a powerful conservative coalition reshaping American politics", "New Right combined economic conservatism (lower taxes, deregulation) with social conservatism (anti-abortion, pro-religion in public life)", "Evangelical groups like Jerry Falwell's Moral Majority became a major Republican political force for the first time", "Reagan coalition — business conservatives + social conservatives + Cold War hawks — realigned US politics for a generation"] },
  { id: 138, cat: "MODERN ERA", term: "Deregulation", bullets: ["Reagan dramatically reduced federal regulations on industries including banking, airlines, energy, and the environment", "Core theory: removing government oversight would unleash free-market competition and grow the economy", "The Savings & Loan crisis of the 1980s–1990s partly resulted from banking deregulation — cost taxpayers ~$124 billion", "Critics argue deregulation contributed to the 2008 financial crisis; supporters say it drove economic growth and consumer choice"] },
  { id: 139, cat: "MODERN ERA", term: "Iran-Contra", bullets: ["1986–1987 scandal: Reagan administration secretly sold arms to Iran (to free hostages) and illegally funneled profits to Nicaraguan Contra rebels", "Congress had explicitly banned aid to the Contras via the Boland Amendment — making the funding illegal", "National Security aide Oliver North orchestrated the scheme; Reagan denied knowledge but accepted responsibility", "Raised serious constitutional questions about presidential power and covert foreign policy; damaged Reagan's second term"] },
  { id: 140, cat: "MODERN ERA", term: "Reagan & End of Cold War", bullets: ["Reagan dramatically increased defense spending and called the USSR an 'Evil Empire,' escalating Cold War pressure", "SDI (Strategic Defense Initiative/'Star Wars'): proposed space-based missile defense system that unsettled Soviet leadership", "Negotiations with Soviet leader Gorbachev led to the INF Treaty (1987): first arms deal to eliminate a whole class of nuclear weapons", "US pressure combined with Soviet internal collapse led to the fall of the Berlin Wall (1989) and USSR dissolution (1991)"] },
  { id: 141, cat: "MODERN ERA", term: "Election of 2000", bullets: ["Presidential race between Republican George W. Bush and Democrat Al Gore — one of the closest in US history", "Gore won the national popular vote; the election turned on Florida's 25 electoral votes", "Disputed ballots ('hanging chads'), a 36-day recount battle, and partisan controversy consumed the nation", "Bush v. Gore (2000): Supreme Court 5–4 stopped the recount — Bush won Florida by 537 votes and the presidency"] },
  { id: 142, cat: "MODERN ERA", term: "September 11, 2001", bullets: ["Al-Qaeda terrorists hijacked 4 commercial airplanes: 2 struck the World Trade Center (NYC), 1 hit the Pentagon, 1 crashed in Pennsylvania after passengers fought back", "2,977 people were killed — the deadliest terrorist attack on American soil and the deadliest single day since the Civil War", "Both World Trade Center towers collapsed; national trauma and sense of vulnerability reshaped American life and policy", "Led directly to the War on Terror, the PATRIOT Act, creation of the Department of Homeland Security, and invasions of Afghanistan and Iraq"] },
  { id: 143, cat: "MODERN ERA", term: "USA PATRIOT Act", bullets: ["Signed into law 45 days after 9/11 — granted the government sweeping surveillance and law enforcement powers to fight terrorism", "Allowed 'roving wiretaps,' monitoring of library records, expanded FBI authority to track communications", "Critics argued it violated 4th Amendment protections against unreasonable searches and endangered civil liberties", "NSA surveillance programs later revealed by Edward Snowden (2013) showed the government went even further than the Act required"] },
  { id: 144, cat: "MODERN ERA", term: "War on Terror", bullets: ["George W. Bush declared a 'War on Terror' after 9/11 — an open-ended global campaign against terrorist organizations", "Led to US invasions of Afghanistan (2001, targeting al-Qaeda/Taliban) and Iraq (2003, falsely claiming WMD stockpiles)", "Created the Department of Homeland Security; established Guantanamo Bay detention facility for terror suspects", "Controversial and costly — over 7,000 US military deaths; raised questions about civil liberties, torture, and executive power"] },
  { id: 145, cat: "MODERN ERA", term: "Taliban & bin Laden", bullets: ["Osama bin Laden: founder of al-Qaeda, the terrorist network responsible for the 9/11 attacks and earlier bombings", "Taliban: Islamist regime that governed Afghanistan (1996–2001) and sheltered bin Laden and al-Qaeda training camps", "US invaded Afghanistan in October 2001 (Operation Enduring Freedom), toppling the Taliban government within months", "Bin Laden evaded capture for nearly 10 years before US Navy SEALs killed him in Abbottabad, Pakistan on May 2, 2011"] },
  { id: 146, cat: "MODERN ERA", term: "Obama Domestic Policy", bullets: ["Barack Obama elected 44th president in 2008 — first African American president in US history; won by a wide margin amid economic crisis", "Affordable Care Act ('Obamacare', 2010): most significant healthcare reform since Medicare/Medicaid — expanded insurance to ~30 million uninsured Americans", "American Recovery and Reinvestment Act (2009): $787 billion stimulus package to fight the Great Recession", "Dodd-Frank Act (2010): financial reform to re-regulate Wall Street and prevent another financial crisis"] },
  { id: 147, cat: "MODERN ERA", term: "Obama Foreign Policy", bullets: ["Ended US combat operations in Iraq (2011) and oversaw a drawdown of forces in Afghanistan", "Signed New START Treaty (2010) with Russia: reduced both nations' deployed strategic nuclear warheads", "Iran Nuclear Deal (JCPOA, 2015): multilateral agreement to limit Iran's nuclear program in exchange for lifting sanctions", "Ordered the Navy SEAL raid that killed Osama bin Laden (May 2, 2011); controversial use of drone strikes in multiple countries"] },

];

export default CARDS;

